import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface LeagueData {
  league: {
    name: string;
    rank: number;
    totalPoints: number;
  };
  topPlayers: {
    name: string;
    team: string;
    points: number;
    position: string;
    performanceTrend: number[];
  }[];
}

export default function Widget() {
  const data = response.data as LeagueData;
  const { league, topPlayers } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#121212' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', fontWeight: 700 }}>
              {league.name}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Rank: {league.rank}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Total Points: {league.totalPoints}
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            {topPlayers.slice(0, 2).map((player, index) => (
              <Box key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.5 }}>
                  <Box>
                    <Typography variant="body2" sx={{ color: '#FFF', fontWeight: 600 }}>
                      {player.name}
                    </Typography>
                    <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                      {player.team} - {player.position}
                    </Typography>
                  </Box>
                  <Box textAlign="right">
                    <Typography variant="body2" sx={{ color: '#FFC107', fontWeight: 500 }}>
                      Points: {player.points}
                    </Typography>
                  </Box>
                </Stack>
                <LineChart
                  height={40}
                  series={[
                    {
                      data: player.performanceTrend,
                      color: '#FFC107',
                      curve: 'natural',
                      showMark: false,
                    },
                  ]}
                  xAxis={[{ data: player.performanceTrend.map((_, i) => i), hide: true }]}
                  margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
                  sx={{
                    '& .MuiLineElement-root': {
                      strokeWidth: 1.5,
                    },
                  }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
